openscad:
$fn = 60;
case_dia = 40; // [20:1:80]
case_height = 8; // [4:1:15]
dial_dia = 34; // [15:1:75]
bezel_height = 2; // [1:0.5:5]
marker_length = 3; // [1:0.5:6]
marker_width = 1.2; // [0.5:0.2:3]
hand_thick = 1.5; // [0.8:0.2:3]
hour_hand_len = 11; // [5:1:20]
minute_hand_len = 15; // [8:1:25]
second_hand_len = 16; // [8:1:25]
crown_dia = 5; // [3:0.5:8]
crown_len = 4; // [2:0.5:8]

module watch() {
    // Black case
    color("black")
    cylinder(d=case_dia, h=case_height);

    // Bezel rim
    color("black")
    translate([0,0,case_height-bezel_height])
    cylinder(d=case_dia+2, h=bezel_height);

    // Bright white dial
    color("white")
    translate([0,0,case_height-1.5])
    cylinder(d=dial_dia, h=1.6);

    // Black hour markers
    for (i = [0:11]) {
        angle = i * 30;
        color("black")
        rotate([0,0,angle])
        translate([dial_dia/2 - marker_length/2 - 1, 0, case_height-0.8])
        cube([marker_length, marker_width, 1.8], center=true);
    }

    // Crown
    color("black")
    translate([case_dia/2 + crown_len/2 - 1, 0, case_height/2])
    rotate([0,90,0])
    cylinder(d=crown_dia, h=crown_len, center=true);

    // Hour hand (black)
    color("black")
    translate([0,0,case_height-0.3])
    rotate([0,0,30])
    cube([hour_hand_len, hand_thick, 1.2], center=false);

    // Minute hand (black)
    color("black")
    translate([0,0,case_height-0.3])
    rotate([0,0,150])
    cube([minute_hand_len, hand_thick*0.8, 1.2], center=false);

    // Second hand (black)
    color("black")
    translate([0,0,case_height-0.3])
    rotate([0,0,270])
    cube([second_hand_len, 0.6, 1.0], center=false);

    // Center pin
    color("black")
    translate([0,0,case_height-0.2])
    cylinder(d=2.5, h=2);
}

watch();
